insert into public.legal_documents (id, type, active, language, text, published_at, created_at, updated_at)
values  (1, 'terms', true, 2, '<h3>Общие положения</h3><p>Настоящие Условия использования регулируют порядок и правила использования туристического сайта. Используя сайт, пользователь подтверждает своё согласие с настоящими условиями.</p><h3>Статус сайта</h3><p>Сайт находится в стадии разработки. Информация, размещённая на сайте, может быть неполной, неточной или изменяться без предварительного уведомления.</p><h4>Функциональность</h4><p>Отдельные функции сайта могут быть недоступны либо работать в тестовом режиме.</p><h4>Информация и предложения</h4><p>Информация о турах, услугах и ценах носит ознакомительный характер и не является публичной офертой.</p><h3>Использование cookies</h3><p>Сайт может использовать файлы cookies и аналогичные технологии для обеспечения корректной работы, анализа использования сайта и улучшения пользовательского опыта.</p><h4>Назначение cookies</h4><p>Cookies могут использоваться для хранения пользовательских предпочтений, а также для сбора обезличенной статистической информации.</p><h4>Управление cookies</h4><p>Пользователь может изменить настройки cookies в своём браузере либо отказаться от их использования, за исключением файлов cookies, необходимых для функционирования сайта.</p><h3>Персональные данные</h3><p>Обработка персональных данных осуществляется в соответствии с применимым законодательством Европейского союза, включая Общий регламент по защите данных (GDPR).</p><h4>Цели обработки данных</h4><p>Персональные данные могут обрабатываться в целях обратной связи, тестирования функциональности сайта и улучшения качества предоставляемых сервисов.</p><h4>Права пользователя</h4><p>Пользователь имеет право на доступ к своим персональным данным, их исправление, удаление, ограничение обработки, а также право отозвать согласие на обработку данных.</p><h3>Ответственность</h3><p>Администрация сайта не несёт ответственности за возможные убытки, возникшие в результате использования сайта или информации, размещённой на нём.</p><h3>Заключительные положения</h3><p>Администрация сайта оставляет за собой право в любое время изменять настоящие Условия использования. Актуальная версия условий публикуется на сайте.</p>', null, '2026-01-28 17:11:34 +00:00', '2026-01-28 17:17:21 +00:00'),
        (2, 'terms', true, 1, '<h3>General provisions</h3><p>These Terms of Use govern the rules and conditions for using the travel website. By using the website, the user confirms acceptance of these terms.</p><h3>Website status</h3><p>The website is under development. Information published on the website may be incomplete, inaccurate, or subject to change without prior notice.</p><h4>Functionality</h4><p>Some website features may be unavailable or operate in test mode.</p><h4>Information and offers</h4><p>Information about tours, services, and prices is provided for informational purposes only and does not constitute a public offer.</p><h3>Use of cookies</h3><p>The website may use cookies and similar technologies to ensure proper operation, analyze website usage, and improve user experience.</p><h4>Purpose of cookies</h4><p>Cookies may be used to store user preferences and to collect anonymized statistical information.</p><h4>Cookie management</h4><p>The user may change cookie settings in their browser or refuse the use of cookies, except for cookies necessary for the operation of the website.</p><h3>Personal data</h3><p>Personal data is processed in accordance with applicable European Union legislation, including the General Data Protection Regulation (GDPR).</p><h4>Purposes of data processing</h4><p>Personal data may be processed for feedback purposes, website functionality testing, and improving the quality of provided services.</p><h4>User rights</h4><p>The user has the right to access their personal data, rectify or delete it, restrict processing, and withdraw consent to data processing.</p><h3>Liability</h3><p>The website administration is not liable for any losses resulting from the use of the website or the information published on it.</p><h3>Final provisions</h3><p>The website administration reserves the right to amend these Terms of Use at any time. The current version of the terms is published on the website.</p>', null, '2026-01-28 17:27:46 +00:00', '2026-01-28 17:27:49 +00:00'),
        (8, 'cookies', true, 1, '<h3>General provisions</h3><p>This Cookies Policy explains how the website uses cookies and similar technologies.</p><h3>What are cookies</h3><p>Cookies are small text files stored on the user’s device when visiting a website.</p><h3>What cookies we use</h3><p>The website may use both essential and analytical cookies.</p><h4>Essential cookies</h4><p>These cookies are necessary for the proper functioning of the website and cannot be disabled.</p><h4>Analytical cookies</h4><p>Analytical cookies are used to collect anonymized information about how users interact with the website.</p><h3>Purposes of using cookies</h3><p>Cookies are used to ensure website functionality, improve user experience, and analyze website usage.</p><h3>Managing cookies</h3><p>The user may manage cookie settings through their browser, including blocking or deleting cookies.</p><h3>Policy changes</h3><p>The website administration may amend this Cookies Policy at any time. The current version is published on the website.</p>', null, '2026-01-28 17:37:16 +00:00', '2026-01-28 17:37:38 +00:00'),
        (3, 'terms', true, 3, '<h3>Postanowienia ogólne</h3><p>Niniejsze warunki użytkowania określają zasady korzystania z serwisu turystycznego. Korzystając z serwisu, użytkownik potwierdza akceptację niniejszych warunków.</p><h3>Status serwisu</h3><p>Serwis znajduje się w fazie rozwoju. Informacje zamieszczone w serwisie mogą być niepełne, nieaktualne lub ulec zmianie bez wcześniejszego powiadomienia.</p><h4>Funkcjonalność</h4><p>Niektóre funkcje serwisu mogą być niedostępne lub działać w trybie testowym.</p><h4>Informacje i oferty</h4><p>Informacje dotyczące wycieczek, usług oraz cen mają charakter wyłącznie informacyjny i nie stanowią oferty publicznej.</p><h3>Wykorzystanie plików cookies</h3><p>Serwis może wykorzystywać pliki cookies oraz podobne technologie w celu zapewnienia prawidłowego działania, analizy korzystania z serwisu oraz poprawy doświadczeń użytkownika.</p><h4>Cel wykorzystania cookies</h4><p>Pliki cookies mogą być wykorzystywane do zapisywania preferencji użytkownika oraz do zbierania zanonimizowanych danych statystycznych.</p><h4>Zarządzanie cookies</h4><p>Użytkownik może zmienić ustawienia plików cookies w swojej przeglądarce lub zrezygnować z ich używania, z wyjątkiem plików cookies niezbędnych do działania serwisu.</p><h3>Dane osobowe</h3><p>Dane osobowe są przetwarzane zgodnie z obowiązującymi przepisami prawa Unii Europejskiej, w tym z Ogólnym Rozporządzeniem o Ochronie Danych (GDPR).</p><h4>Cele przetwarzania danych</h4><p>Dane osobowe mogą być przetwarzane w celach kontaktowych, testowania funkcjonalności serwisu oraz poprawy jakości świadczonych usług.</p>', null, '2026-01-28 17:28:01 +00:00', '2026-01-28 17:28:06 +00:00'),
        (4, 'privacy', true, 2, '<h3>Общие положения</h3><p>Настоящая Политика конфиденциальности описывает порядок сбора, использования и защиты персональных данных пользователей туристического сайта.</p><h3>Какие данные мы собираем</h3><p>В рамках использования сайта могут собираться персональные данные, предоставляемые пользователем добровольно, а также технические данные.</p><h4>Данные, предоставляемые пользователем</h4><p>К таким данным могут относиться имя, адрес электронной почты и иная информация, передаваемая через формы на сайте.</p><h4>Технические данные</h4><p>Автоматически могут собираться данные о браузере, IP-адресе, устройстве пользователя, а также данные cookies.</p><h3>Цели обработки данных</h3><p>Персональные данные обрабатываются в целях обеспечения работы сайта, обратной связи с пользователями, тестирования функциональности и улучшения качества сервиса.</p><h3>Правовые основания обработки</h3><p>Обработка персональных данных осуществляется на основании согласия пользователя, а также в рамках законных интересов администратора сайта в соответствии с GDPR.</p><h3>Хранение и защита данных</h3><p>Персональные данные хранятся не дольше, чем это необходимо для достижения целей обработки, и защищаются с использованием разумных технических и организационных мер.</p><h3>Права пользователя</h3><p>Пользователь имеет право на доступ к своим персональным данным, их исправление, удаление, ограничение обработки, перенос данных, а также право отозвать согласие в любое время.</p><h3>Передача данных третьим лицам</h3><p>Персональные данные не передаются третьим лицам, за исключением случаев, предусмотренных законодательством или необходимых для работы сайта.</p><h3>Заключительные положения</h3><p>Администрация сайта оставляет за собой право вносить изменения в настоящую Политику конфиденциальности. Актуальная версия документа публикуется на сайте.</p>', null, '2026-01-28 17:33:13 +00:00', '2026-01-28 17:33:21 +00:00'),
        (5, 'cookies', true, 2, '<h3>Общие положения</h3><p>Настоящая Политика использования cookies объясняет, каким образом сайт использует файлы cookies и аналогичные технологии.</p><h3>Что такое cookies</h3><p>Cookies — это небольшие текстовые файлы, сохраняемые на устройстве пользователя при посещении сайта.</p><h3>Какие cookies мы используем</h3><p>Сайт может использовать как обязательные, так и аналитические файлы cookies.</p><h4>Обязательные cookies</h4><p>Эти cookies необходимы для корректной работы сайта и не могут быть отключены.</p><h4>Аналитические cookies</h4><p>Аналитические cookies используются для сбора обезличенной информации о том, как пользователи взаимодействуют с сайтом.</p><h3>Цели использования cookies</h3><p>Cookies используются для обеспечения функциональности сайта, улучшения пользовательского опыта и анализа использования сайта.</p><h3>Управление cookies</h3><p>Пользователь может управлять настройками cookies через настройки своего браузера, включая возможность их блокировки или удаления.</p><h3>Изменения политики</h3><p>Администрация сайта может изменять настоящую Политику использования cookies без предварительного уведомления. Актуальная версия публикуется на сайте.</p>', null, '2026-01-28 17:33:34 +00:00', '2026-01-28 17:33:37 +00:00'),
        (6, 'privacy', true, 1, '<h3>General provisions</h3><p>This Privacy Policy describes how personal data of users of the travel website is collected, used, and protected.</p><h3>What data we collect</h3><p>When using the website, personal data voluntarily provided by the user as well as technical data may be collected.</p><h4>User-provided data</h4><p>This may include name, email address, and other information submitted through forms on the website.</p><h4>Technical data</h4><p>Technical data such as browser type, IP address, user device information, and cookies may be collected automatically.</p><h3>Purposes of data processing</h3><p>Personal data is processed to ensure website operation, communicate with users, test functionality, and improve service quality.</p><h3>Legal basis for processing</h3><p>Personal data is processed based on the user’s consent and the legitimate interests of the website administrator in accordance with the GDPR.</p><h3>Data storage and protection</h3><p>Personal data is stored only for as long as necessary to achieve processing purposes and is protected using reasonable technical and organizational measures.</p><h3>User rights</h3><p>The user has the right to access, rectify, delete, restrict processing, transfer their personal data, and withdraw consent at any time.</p><h3>Data sharing with third parties</h3><p>Personal data is not shared with third parties, except where required by law or necessary for website operation.</p><h3>Final provisions</h3><p>The website administration reserves the right to amend this Privacy Policy at any time. The current version is published on the website.</p>', null, '2026-01-28 17:34:55 +00:00', '2026-01-28 17:34:59 +00:00'),
        (7, 'privacy', true, 3, '<h3>Postanowienia ogólne</h3><p>Niniejsza Polityka prywatności opisuje zasady zbierania, wykorzystywania oraz ochrony danych osobowych użytkowników serwisu turystycznego.</p><h3>Jakie dane zbieramy</h3><p>Podczas korzystania z serwisu mogą być zbierane dane osobowe dobrowolnie przekazywane przez użytkownika oraz dane techniczne.</p><h4>Dane przekazywane przez użytkownika</h4><p>Mogą to być imię, adres e-mail oraz inne informacje przekazywane za pośrednictwem formularzy dostępnych w serwisie.</p><h4>Dane techniczne</h4><p>Automatycznie mogą być zbierane dane dotyczące przeglądarki, adresu IP, urządzenia użytkownika oraz plików cookies.</p><h3>Cele przetwarzania danych</h3><p>Dane osobowe są przetwarzane w celu zapewnienia działania serwisu, kontaktu z użytkownikami, testowania funkcjonalności oraz poprawy jakości usług.</p><h3>Podstawa prawna przetwarzania</h3><p>Dane osobowe są przetwarzane na podstawie zgody użytkownika oraz prawnie uzasadnionego interesu administratora serwisu, zgodnie z przepisami GDPR.</p><h3>Przechowywanie i ochrona danych</h3><p>Dane osobowe są przechowywane wyłącznie przez okres niezbędny do realizacji celów przetwarzania oraz chronione przy użyciu odpowiednich środków technicznych i organizacyjnych.</p><h3>Prawa użytkownika</h3><p>Użytkownik ma prawo dostępu do swoich danych osobowych, ich poprawiania, usunięcia, ograniczenia przetwarzania, przenoszenia danych oraz cofnięcia zgody w dowolnym momencie.</p><h3>Przekazywanie danych osobom trzecim</h3><p>Dane osobowe nie są przekazywane osobom trzecim, z wyjątkiem przypadków wymaganych przepisami prawa lub niezbędnych do działania serwisu.</p><h3>Postanowienia końcowe</h3><p>Administrator serwisu zastrzega sobie prawo do zmiany niniejszej Polityki prywatności. Aktualna wersja dokumentu jest publikowana w serwisie.</p>', null, '2026-01-28 17:35:11 +00:00', '2026-01-28 17:35:14 +00:00'),
        (9, 'cookies', true, 3, '<h3>Postanowienia ogólne</h3><p>Niniejsza Polityka cookies wyjaśnia, w jaki sposób serwis wykorzystuje pliki cookies oraz podobne technologie.</p><h3>Czym są cookies</h3><p>Cookies to niewielkie pliki tekstowe zapisywane na urządzeniu użytkownika podczas korzystania z serwisu.</p><h3>Jakie cookies wykorzystujemy</h3><p>Serwis może wykorzystywać zarówno niezbędne, jak i analityczne pliki cookies.</p><h4>Niezbędne cookies</h4><p>Pliki te są konieczne do prawidłowego działania serwisu i nie mogą zostać wyłączone.</p><h4>Analityczne cookies</h4><p>Analityczne pliki cookies służą do zbierania zanonimizowanych informacji o sposobie korzystania z serwisu.</p><h3>Cele wykorzystywania cookies</h3><p>Cookies są wykorzystywane w celu zapewnienia funkcjonalności serwisu, poprawy doświadczeń użytkownika oraz analizy korzystania z serwisu.</p><h3>Zarządzanie cookies</h3><p>Użytkownik może zarządzać ustawieniami plików cookies w swojej przeglądarce, w tym blokować lub usuwać cookies.</p><h3>Zmiany polityki</h3><p>Administrator serwisu może wprowadzać zmiany w niniejszej Polityce cookies. Aktualna wersja dokumentu jest publikowana w serwisie.</p>', null, '2026-01-28 17:37:50 +00:00', '2026-01-28 17:37:53 +00:00'),
        (10, 'refund', true, 1, '<h3>General provisions</h3><p>This Refund Policy defines the rules for cancellation of services and refund of payments made through the travel website.</p><h3>Website status</h3><p>The website is under development. Information regarding refunds may be incomplete and subject to change.</p><h3>Cancellation of services</h3><p>Conditions for cancellation of tours or services may depend on specific offers and partners providing the services.</p><h4>Cancellation request</h4><p>To request a cancellation, the user may be required to contact the website administration using the available contact details.</p><h3>Refund conditions</h3><p>The possibility and amount of a refund depend on the terms of the selected service, time of cancellation, and applicable partner policies.</p><h4>Refund method</h4><p>Refunds, if applicable, are made using the same payment method that was used for the original transaction, unless otherwise agreed.</p><h3>Processing time</h3><p>Refund processing times may vary depending on the payment provider and internal procedures.</p><h3>Liability</h3><p>The website administration is not responsible for delays or refusals of refunds resulting from third-party service providers.</p><h3>Final provisions</h3><p>The website administration reserves the right to amend this Refund Policy at any time. The current version is published on the website.</p>', null, '2026-01-28 17:39:38 +00:00', '2026-01-28 17:39:46 +00:00'),
        (11, 'refund', true, 3, '<h3>Postanowienia ogólne</h3><p>Niniejsza Polityka zwrotów określa zasady anulowania usług oraz zwrotu płatności dokonanych za pośrednictwem serwisu turystycznego.</p><h3>Status serwisu</h3><p>Serwis znajduje się w fazie rozwoju. Informacje dotyczące zwrotów mogą być niepełne oraz ulegać zmianom.</p><h3>Anulowanie usług</h3><p>Warunki anulowania wycieczek lub usług mogą zależeć od konkretnej oferty oraz partnerów świadczących usługi.</p><h4>Wniosek o anulowanie</h4><p>Aby zgłosić anulowanie, użytkownik może być zobowiązany do skontaktowania się z administratorem serwisu za pomocą dostępnych danych kontaktowych.</p><h3>Warunki zwrotu</h3><p>Możliwość oraz wysokość zwrotu zależą od warunków wybranej usługi, momentu anulowania oraz zasad obowiązujących u partnerów.</p><h4>Sposób zwrotu</h4><p>Zwrot środków, jeżeli przysługuje, dokonywany jest tą samą metodą płatności, która została użyta do dokonania pierwotnej transakcji, o ile nie uzgodniono inaczej.</p><h3>Czas realizacji zwrotu</h3><p>Czas realizacji zwrotu może się różnić w zależności od operatora płatności oraz procedur wewnętrznych.</p><h3>Odpowiedzialność</h3><p>Administrator serwisu nie ponosi odpowiedzialności za opóźnienia lub odmowy zwrotów wynikające z działań podmiotów trzecich.</p><h3>Postanowienia końcowe</h3><p>Administrator serwisu zastrzega sobie prawo do zmiany niniejszej Polityki zwrotów w dowolnym momencie. Aktualna wersja dokumentu jest publikowana w serwisie.</p>', null, '2026-01-28 17:39:59 +00:00', '2026-01-28 17:40:07 +00:00'),
        (12, 'refund', true, 2, '<h3>Общие положения</h3><p>Настоящая Политика возврата средств определяет условия отмены услуг и возврата платежей, совершённых через туристический сайт.</p><h3>Статус сайта</h3><p>Сайт находится в стадии разработки. Информация, связанная с возвратами средств, может быть неполной и изменяться без предварительного уведомления.</p><h3>Отмена услуг</h3><p>Условия отмены туров или услуг могут зависеть от конкретного предложения и правил партнёров, предоставляющих соответствующие услуги.</p><h4>Запрос на отмену</h4><p>Для оформления отмены пользователь может быть обязан связаться с администрацией сайта с использованием доступных контактных данных.</p><h3>Условия возврата средств</h3><p>Возможность и размер возврата средств зависят от условий выбранной услуги, времени отмены и правил, установленных партнёрами.</p><h4>Способ возврата средств</h4><p>Возврат средств, если он предусмотрен, осуществляется тем же способом оплаты, который был использован при совершении исходного платежа, если иное не согласовано сторонами.</p><h3>Сроки обработки возвратов</h3><p>Сроки обработки возвратов могут различаться в зависимости от платёжного провайдера и внутренних процедур.</p><h3>Ответственность</h3><p>Администрация сайта не несёт ответственности за задержки или отказ в возврате средств, вызванные действиями третьих лиц.</p><h3>Заключительные положения</h3><p>Администрация сайта оставляет за собой право в любое время изменять настоящую Политику возврата средств. Актуальная версия документа публикуется на сайте.</p>', null, '2026-01-28 17:40:51 +00:00', '2026-01-28 17:40:54 +00:00');